                            child: Container(
                              color: ColorPallete.textSecondary.withOpacity(0.25),
                              child: const Center(
                                child: CircularProgressIndicator(color: ColorPallete.error),
                              ),
                            ),
                          ),
                      ],
                    );
                  },
                ),
              ],
            ),
          ),
        ),
      ),
    );
  }

  Widget _appBar(BuildContext context) {
