import 'package:hackathon/features/projects/presentation/blocs/project_bloc/project_event.dart';
import 'package:hackathon/features/projects/presentation/blocs/project_bloc/project_state.dart';
import 'package:hackathon/features/projects/presentation/widgets/project_status_badge.dart';
import 'package:hackathon/features/tasks/presentation/blocs/task_bloc/task_bloc.dart';
import 'package:hackathon/globals/constants/user.dart';
import 'package:hackathon/globals/constants/color_pallete.dart';
import 'package:intl/intl.dart';

class ProjectDetailPage extends StatefulWidget {
  static const String routePath = '/projects-detail';
  static const String routeName = 'projects-detail';
  final int projectId;

  const ProjectDetailPage({
    super.key,
    required this.projectId,
  });

  @override
  State<ProjectDetailPage> createState() => _ProjectDetailPageState();
}

class _ProjectDetailPageState extends State<ProjectDetailPage> with SingleTickerProviderStateMixin {
  late TabController _tabController;

  @override
  void initState() {
    super.initState();
    _tabController = TabController(length: 2, vsync: this);
  }

  @override
  void dispose() {
    _tabController.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    final width = MediaQuery.of(context).size.width;
    final height = MediaQuery.of(context).size.height;

    return Container(
      decoration: const BoxDecoration(
        gradient: LinearGradient(
          colors: [ColorPallete.backgroundPrimary, ColorPallete.backgroundSecondary],
          begin: Alignment.topCenter,
          end: Alignment.bottomCenter,
        ),
      ),
      child: BlocProvider(
        create: (context) => getIt<ProjectsBloc>()..add(LoadProjectDetailEvent(widget.projectId)),
        child: Scaffold(
          backgroundColor: ColorPallete.transparent,
          appBar: AppBar(
            backgroundColor: ColorPallete.transparent,
            elevation: 0,
            leading: IconButton(
              icon: const Icon(Icons.arrow_back, color: ColorPallete.textPrimary),
              onPressed: () => context.pop(),
            ),
            title: const Text(
              'Project Details',
              style: TextStyle(color: ColorPallete.textPrimary, fontWeight: FontWeight.bold),
            ),
          ),
          body: BlocConsumer<ProjectsBloc, ProjectState>(
            listener: (context, state) {
              if (state is ProjectActionSuccess) {
                ElegantNotification.success(
                  title: const Text("Success"),
                  description: Text(state.message),
                ).show(context);
                context.read<ProjectsBloc>().add(LoadProjectDetailEvent(widget.projectId));
              } else if (state is ProjectError) {
                ElegantNotification.error(
                  title: const Text("Error"),
                  description: Text(state.message),
                ).show(context);
              }
            },
            builder: (context, state) {
              if (state is ProjectLoading) {
                return const Center(child: CircularProgressIndicator.adaptive(valueColor: AlwaysStoppedAnimation(ColorPallete.textPrimary)));
              } else if (state is ProjectDetailLoaded) {
                final project = state.project;
                return Padding(
                  padding: EdgeInsets.symmetric(
                    horizontal: width * 0.04,
                    vertical: height * 0.01,
                  ),
                  child: Column(
                    crossAxisAlignment: CrossAxisAlignment.start,
                    children: [
                      _buildHeaderCard(context, project),
                      const SizedBox(height: 20),
                      _buildTabBar(),
                      const SizedBox(height: 16),
                      Expanded(
                        child: TabBarView(
                          controller: _tabController,
                          children: [
                            _buildMilestonesTab(context, project),
                            _buildTasksTab(context, project),
                          ],
                        ),
                      ),
                    ],
                  ),
                );
              } else if (state is ProjectError) {
                return _buildErrorState(context, state.message);
              } else {
                return const Center(child: CircularProgressIndicator.adaptive(valueColor: AlwaysStoppedAnimation(ColorPallete.textPrimary)));
              }
            },
          ),
        ),
      ),
    );
  }

  Widget _buildHeaderCard(BuildContext context, Project project) {
    // Calculate progress
    double progress = 0.0;
    if (project.milestones.isNotEmpty) {
      final completed = project.milestones.where((m) => m.status.toLowerCase() == 'completed').length;
      progress = completed / project.milestones.length;
    } else {
      switch (project.status.toLowerCase()) {
        case 'planning':
          progress = 0.15;
          break;
        case 'active':
          progress = 0.50;
          break;
        case 'completed':
          progress = 1.0;
          break;
        case 'on_hold':
        case 'paused':
          progress = 0.35;
          break;
        default:
          progress = 0.0;
      }
    }

    final dateRangeStr = '${DateFormat('MMMM dd, yyyy').format(project.startDate)} - ${DateFormat('MMMM dd, yyyy').format(project.endDate)}';

    return Container(
      padding: const EdgeInsets.all(24),
      decoration: BoxDecoration(
        color: ColorPallete.backgroundPrimary,
        borderRadius: BorderRadius.circular(16),
        border: Border.all(color: ColorPallete.divider),
      ),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.start,
        children: [
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            crossAxisAlignment: CrossAxisAlignment.start,
            children: [
              Expanded(
                child: Column(
                  crossAxisAlignment: CrossAxisAlignment.start,
                  children: [
                    Text(
                      project.name,
                      style: const TextStyle(color: ColorPallete.textPrimary, fontSize: 24, fontWeight: FontWeight.bold),
                    ),
                    const SizedBox(height: 8),
                    Text(
                      project.description.isNotEmpty ? project.description : 'No description provided.',
                      style: const TextStyle(color: ColorPallete.textSecondary, fontSize: 14, height: 1.4),
                    ),
                  ],
                ),
              ),
              const SizedBox(width: 20),
              Column(
                crossAxisAlignment: CrossAxisAlignment.end,
                children: [
                  Row(
                    children: [
                      ProjectStatusBadge(text: project.status),
                      const SizedBox(width: 8),
                      ProjectStatusBadge(text: project.priority, isPriority: true),
                    ],
                  ),
                  const SizedBox(height: 12),
                  Row(
                    children: [
                      const Icon(Icons.people_outline_rounded, size: 16, color: ColorPallete.textDisabled),
                      const SizedBox(width: 6),
                      Text('Team ID: ${project.teamId}', style: const TextStyle(color: ColorPallete.textDisabled, fontSize: 13)),
                    ],
                  ),
                ],
              ),
            ],
          ),
          const SizedBox(height: 20),
          const Divider(color: ColorPallete.divider),
          const SizedBox(height: 16),
          Row(
            mainAxisAlignment: MainAxisAlignment.spaceBetween,
            children: [
              Row(
                children: [
                  const Icon(Icons.calendar_month_rounded, size: 16, color: ColorPallete.textSecondary),
                  const SizedBox(width: 8),
                  Text(
                    dateRangeStr,
                    style: const TextStyle(color: ColorPallete.textSecondary, fontSize: 14, fontWeight: FontWeight.w500),
                  ),
                ],
              ),
              Row(
                children: [
                  const Text(
                    'Progress: ',
                    style: TextStyle(color: ColorPallete.textDisabled, fontSize: 14, fontWeight: FontWeight.bold),
                  ),
                  Text(
                    '${(progress * 100).toInt()}%',
                    style: TextStyle(color: ColorPallete.statusColor('approved'), fontSize: 15, fontWeight: FontWeight.bold),
                  ),
                ],
              ),
            ],
          ),
          const SizedBox(height: 10),
          ClipRRect(
            borderRadius: BorderRadius.circular(4),
            child: LinearProgressIndicator(
              value: progress,
              backgroundColor: ColorPallete.textPrimary.withAlpha(15),
              valueColor: AlwaysStoppedAnimation<Color>(ColorPallete.statusColor('approved')),
              minHeight: 8,
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildTabBar() {
    return Container(
      decoration: BoxDecoration(
        color: ColorPallete.backgroundPrimary,
        borderRadius: BorderRadius.circular(12),
        border: Border.all(color: ColorPallete.divider),
      ),
      child: TabBar(
        controller: _tabController,
        indicatorSize: TabBarIndicatorSize.tab,
        dividerColor: ColorPallete.transparent,
        indicator: BoxDecoration(
          color: ColorPallete.textPrimary.withAlpha(15),
          borderRadius: BorderRadius.circular(10),
        ),
        labelColor: ColorPallete.textPrimary,
        unselectedLabelColor: ColorPallete.textDisabled,
        tabs: const [
          Tab(
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(Icons.flag_outlined, size: 18),
                SizedBox(width: 8),
                Text('Milestones', style: TextStyle(fontWeight: FontWeight.bold)),
              ],
            ),
          ),
          Tab(
            child: Row(
              mainAxisAlignment: MainAxisAlignment.center,
              children: [
                Icon(Icons.assignment_outlined, size: 18),
                SizedBox(width: 8),
                Text('Tasks', style: TextStyle(fontWeight: FontWeight.bold)),
              ],
            ),
          ),
        ],
      ),
    );
  }

  Widget _buildMilestonesTab(BuildContext parentContext, Project project) {
    return Column(
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        Row(
          mainAxisAlignment: MainAxisAlignment.spaceBetween,
          children: [
            Text(
              '${project.milestones.length} Milestones',
              style: const TextStyle(color: ColorPallete.textPrimary, fontSize: 16, fontWeight: FontWeight.bold),
            ),
            ElevatedButton.icon(
              style: ElevatedButton.styleFrom(
                backgroundColor: ColorPallete.textPrimary,
                foregroundColor: ColorPallete.textSecondary,
                padding: const EdgeInsets.symmetric(horizontal: 16, vertical: 10),
                shape: RoundedRectangleBorder(borderRadius: BorderRadius.circular(10)),
              ),
              icon: const Icon(Icons.add, size: 16),
              label: const Text('Add Milestone', style: TextStyle(fontWeight: FontWeight.bold, fontSize: 12)),
              onPressed: () => _showMilestoneDialog(parentContext, project.id, null),
            ),
          ],
        ),
        const SizedBox(height: 12),
        Expanded(
          child: project.milestones.isEmpty
              ? _buildEmptyTabState(Icons.flag_outlined, 'No milestones defined', 'Define major project milestones to track execution progress.')
              : ListView.builder(
                  itemCount: project.milestones.length,
                  itemBuilder: (context, index) {
                    final milestone = project.milestones[index];
                    return _buildMilestoneTile(parentContext, milestone);
                  },
                ),
        ),
      ],
    );
  }

  Widget _buildMilestoneTile(BuildContext parentContext, Milestone milestone) {
    final cleanStatus = milestone.status.toLowerCase();
    final isCompleted = cleanStatus == 'completed';

    Color statusColor;
    if (isCompleted) {
      statusColor = const Color(0xFF34D399); // emerald-400
    } else if (milestone.isOverdue) {
      statusColor = const Color(0xFFF87171); // red-400
    } else {
      statusColor = const Color(0xFFFACC15); // yellow-400
    }

    return Container(
      margin: const EdgeInsets.only(bottom: 12),
      padding: const EdgeInsets.all(16),
      decoration: BoxDecoration(
        color: ColorPallete.backgroundPrimary,
        borderRadius: BorderRadius.circular(12),
        border: Border.all(
          color: milestone.isOverdue && !isCompleted ? ColorPallete.error.withAlpha(50) : ColorPallete.divider,
        ),
      ),
      child: Row(
        children: [
          Icon(
            isCompleted ? Icons.check_circle_rounded : Icons.radio_button_unchecked_rounded,
            color: isCompleted ? const Color(0xFF34D399) : ColorPallete.textDisabled,
            size: 24,
          ),
          const SizedBox(width: 14),
          Expanded(
            child: Column(
              crossAxisAlignment: CrossAxisAlignment.start,
              children: [
                Text(
                  milestone.title,
                  style: TextStyle(
                    color: ColorPallete.textPrimary,
                    fontSize: 15,
                    fontWeight: FontWeight.bold,
                    decoration: isCompleted ? TextDecoration.lineThrough : null,
                  ),
                ),
                const SizedBox(height: 4),
                Text(
                  milestone.description.isNotEmpty ? milestone.description : 'No details provided.',
                  style: const TextStyle(color: ColorPallete.textSecondary, fontSize: 13),
                ),
                const SizedBox(height: 8),
                Row(
                  children: [
                    Icon(Icons.calendar_today_rounded, size: 11, color: milestone.isOverdue && !isCompleted ? ColorPallete.error : ColorPallete.textDisabled),
                    const SizedBox(width: 4),
                    Text(
                      'Due: ${DateFormat('MMM dd, yyyy').format(milestone.dueDate)}',
                      style: TextStyle(
                        color: milestone.isOverdue && !isCompleted ? ColorPallete.error : ColorPallete.textSecondary,
                        fontSize: 11,
                        fontWeight: milestone.isOverdue && !isCompleted ? FontWeight.bold : FontWeight.normal,
                      ),
                    ),
                    if (milestone.isOverdue && !isCompleted) ...[
                      const SizedBox(width: 8),
                      Container(
                        padding: const EdgeInsets.symmetric(horizontal: 6, vertical: 2),
                        decoration: BoxDecoration(color: const Color(0xFF7F1D1D), borderRadius: BorderRadius.circular(4)),
                        child: const Text('OVERDUE', style: TextStyle(color: Color(0xFFF87171), fontSize: 9, fontWeight: FontWeight.bold)),
                      ),
                    ],
                  ],
                ),
              ],
            ),
          ),
          const SizedBox(width: 12),
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
            decoration: BoxDecoration(
              color: statusColor.withAlpha(20),
              borderRadius: BorderRadius.circular(8),
              border: Border.all(color: statusColor.withAlpha(50)),
            ),
            child: Text(
              milestone.status.toUpperCase(),
              style: TextStyle(color: statusColor, fontSize: 10, fontWeight: FontWeight.bold),
            ),
          ),
          const SizedBox(width: 8),
          PopupMenuButton<String>(
            icon: const Icon(Icons.more_vert_rounded, color: ColorPallete.textSecondary),
            color: ColorPallete.backgroundPrimary,
            onSelected: (val) {
              if (val == 'edit') {
                _showMilestoneDialog(parentContext, milestone.projectId, milestone);
              } else if (val == 'delete') {
                _confirmDeleteMilestone(parentContext, milestone);
              }
            },
            itemBuilder: (context) => [
              const PopupMenuItem(
                value: 'edit',
                child: Row(
                  children: [
                    Icon(Icons.edit_outlined, size: 16, color: ColorPallete.textSecondary),
                    SizedBox(width: 8),
                    Text('Edit Details', style: TextStyle(color: ColorPallete.textSecondary)),
                  ],
                ),
              ),
              const PopupMenuItem(
                value: 'delete',
                child: Row(
                  children: [
                    Icon(Icons.delete_outline_rounded, size: 16, color: ColorPallete.error),
                    SizedBox(width: 8),
                    Text('Delete Milestone', style: TextStyle(color: ColorPallete.error)),
                  ],
                ),
              ),
            ],
          ),
        ],
      ),
    );
  }

  Widget _buildTasksTab(BuildContext context, Project project) {
    return BlocBuilder<TaskBloc, TaskState>(
      builder: (context, state) {
        if (state is TaskLoading) {
          return const Center(child: CircularProgressIndicator.adaptive());
        } else if (state is TaskSuccess) {
          final projectTasks = state.tasks.where((t) => t.projectId == project.id).toList();

          if (projectTasks.isEmpty) {
            return _buildEmptyTabState(Icons.assignment_outlined, 'No tasks linked to project', 'Create tasks and link them to this project to keep your workflow synchronized.');
          }

          return ListView.builder(
            itemCount: projectTasks.length,
            itemBuilder: (context, index) {
              final task = projectTasks[index];
              return Container(
                margin: const EdgeInsets.only(bottom: 12),
                padding: const EdgeInsets.all(16),
                decoration: BoxDecoration(
                  color: ColorPallete.backgroundPrimary,
                  borderRadius: BorderRadius.circular(12),
                  border: Border.all(color: ColorPallete.divider),
                ),
                child: Row(
                  children: [
                    Icon(
                      task.type.toLowerCase() == 'bug' ? Icons.bug_report_outlined : Icons.assignment_outlined,
                      color: task.type.toLowerCase() == 'bug' ? ColorPallete.error : ColorPallete.statusColor('approved'),
                      size: 20,
                    ),
                    const SizedBox(width: 14),
                    Expanded(
                      child: Column(
                        crossAxisAlignment: CrossAxisAlignment.start,
                        children: [
                          Text(
                            task.title,
                            style: const TextStyle(color: ColorPallete.textPrimary, fontSize: 14, fontWeight: FontWeight.bold),
                          ),
                          const SizedBox(height: 4),
                          Text(
                            task.description ?? 'No details provided.',
                            style: const TextStyle(color: ColorPallete.textSecondary, fontSize: 12),
                            maxLines: 1,
                            overflow: TextOverflow.ellipsis,
                          ),
                          const SizedBox(height: 6),
                          Row(
                            children: [
                              Text('Priority: ${task.priority}', style: const TextStyle(color: ColorPallete.textDisabled, fontSize: 11)),
                              const SizedBox(width: 12),
                              Text('Assigned User ID: ${task.assignedTo}', style: const TextStyle(color: ColorPallete.textDisabled, fontSize: 11)),
                            ],
                          ),
                        ],
                      ),
                    ),
                    const SizedBox(width: 12),
                    Container(
                      padding: const EdgeInsets.symmetric(horizontal: 8, vertical: 4),
                      decoration: BoxDecoration(
                        color: ColorPallete.textPrimary.withAlpha(10),
                        borderRadius: BorderRadius.circular(8),
                      ),
                      child: Text(
                        task.status,
                        style: const TextStyle(color: ColorPallete.textSecondary, fontSize: 10, fontWeight: FontWeight.bold),
                      ),
                    ),
                  ],
                ),
              );
            },
          );
        } else {
          return _buildEmptyTabState(Icons.assignment_outlined, 'Tasks data unavailable', 'Ensure you have permissions to load workspace tasks.');
        }
      },
    );
  }

  void _showMilestoneDialog(BuildContext parentContext, int projectId, Milestone? milestoneToEdit) {
