                            color: ColorPallete.backgroundTertiary,
                            borderRadius: BorderRadius.circular(10)),
                        height: sheight * 0.87,
                        // width: swidth * 0.8,
                        child: Column(
                          mainAxisSize: MainAxisSize.max,
                          children: [
                            Align(
                              alignment: Alignment.topCenter,
                              child: CustomAppBar(children: [
                                const Icon(
                                  Icons.person,
                                ),
                                Text(selectedChatName),
                                const Spacer(),
                                GestureDetector(
                                  child: const Icon(Icons.call),
                                  onTap: () {
                                    context.push(CallPage.routePath, extra: {
                                      "isCalling": true,
                                      'chat': selectedChat
                                    });
                                  },
                                ),
                                SizedBox(
                                  width: swidth * 0.02,
                                )
                              ]),
                            ),
                            if (isChatSelected)
                              BlocListener<MessageBloc, MessageState>(
                                listener: (context, state) {
                                  if (state is MessageErrorState) {
                                    ScaffoldMessenger.of(context).showSnackBar(
                                        SnackBar(
                                            content: Text(
                                                state.errorModel.message)));
                                  }
                                },
                                child: Expanded(
                                    child: StreamBuilder<List<MessageEntity>>(
                                  stream: getIt<MessageRepository>()
                                      .getMessages(selectedChat!.roomId),
                                  builder: ((BuildContext context,
                                      AsyncSnapshot<List<MessageEntity>> snapshot) {
                                    if (snapshot.hasError) {
                                      return Text(snapshot.error.toString());
                                    }
                                    if (snapshot.connectionState ==
                                        ConnectionState.waiting) {
                                      return const Center(
                                          child: CircularProgressIndicator());
                                    }
                                    if (snapshot.hasData &&
                                        snapshot.data != null) {
                                      final List<MessageEntity> data = List<MessageEntity>.from(snapshot.data!);
                                      WidgetsBinding.instance
                                          .addPostFrameCallback((_) {
                                        _scrollController.jumpTo(
                                          _scrollController
                                              .position.maxScrollExtent,
                                        );
                                      });
                                      return ListView.builder(
                                        controller: _scrollController,
                                        itemCount: data.length,
                                        itemBuilder: (context, index) {
                                          return ChatBubble(
                                              chatMessageEntity: data[index]);
                                        },
                                      );
                                    }
                                    return const SizedBox();
                                  }),
                                )),
                              ),
                            Align(
                              alignment: Alignment.bottomLeft,
                              child: Container(
                                  decoration: BoxDecoration(
                                      color: ColorPallete.textSecondary,
                                      borderRadius: BorderRadius.circular(10)),
                                  child: Row(
                                    children: [
                                      Flexible(
                                        flex: 3,
                                        child: TextField(
                                          controller: controller,
                                          decoration: const InputDecoration(
                                            border: InputBorder.none,
                                          ),
                                        ),
                                      ),
                                      Flexible(
                                        flex: 1,
                                        child: Row(
                                          crossAxisAlignment:
                                              CrossAxisAlignment.start,
                                          mainAxisSize: MainAxisSize.max,
                                          mainAxisAlignment:
                                              MainAxisAlignment.spaceEvenly,
                                          children: [
                                            GestureDetector(
                                              child: const Icon(Icons.send),
                                              onTap: () {
                                                final text = controller.text.trim();
                                                if (text.isEmpty) return; // Don't send empty messages

                                                context.read<MessageBloc>().add(
                                                    SendMessageEvent(
                                                        messageParams: MessageParams(
                                                            message: text,
                                                            senderId:
                                                                getIt<User>()
                                                                    .user!
                                                                    .id
                                                                    .toString(),
                                                            receiverId:
                                                                selectedChat!.id
                                                                    .toString(),
                                                            receiverName:
                                                                selectedChatName,
                                                            isSender: true,
                                                            roomId: selectedChat!
                                                                .roomId,
                                                            createdAt:
                                                                DateTime.now(),
                                                            senderName: getIt<
                                                                    User>()
                                                                .user!
                                                                .firstName)));

                                                controller.clear();
                                              },
                                            ),
                                          ],
                                        ),
                                      ),
                                    ],
                                  )),
                            )
                          ],
                        ),
                      ),
                    ))
              ],
            ),
          ],
        ),
      ),
    );
  }

  CustomAppBar _customChatBar() {
    return CustomAppBar(children: [
      if (!isChatSelected) const Text("Chats"),
      if (isChatSelected) Text("Chats > $selectedChatName"),
      const Spacer(),
      IconButton(
        onPressed: () {
          _chatPageKey.currentState?.openDrawer();
        },
        icon: const Icon(
          Icons.menu,
          color: ColorPallete.textPrimary,
        ),
      ),
    ]);
  }
}

