    return {
      'plan_id': planId,
      'plan_name': planName,
      'plan_status': planStatus,
      'max_employees': maxEmployees,
      'plan_start_date': planStartDate?.toIso8601String(),
      'plan_end_date': planEndDate?.toIso8601String(),
    };
  }
}

