                            ),
                            onPressed: isLoading
                                ? null
                                : () => _showDeleteConfirmation(context),
                            child: isLoading
                                ? const SizedBox(
                                    width: 20,
                                    height: 20,
                                    child: CircularProgressIndicator(
                                      strokeWidth: 2,
                                      valueColor: AlwaysStoppedAnimation<Color>(ColorPallete.textPrimary),
