      id: json['id'] as int?,
      leaveType: json['leave_type'] as String? ?? '',
      maxDays: json['max_days'] as int? ?? 0,
      description: json['description'] as String? ?? '',
    );
  }

  Map<String, dynamic> toJson() {
    return {
      'id': id,
      'leave_type': leaveType,
      'max_days': maxDays,
      'description': description,
    };
  }
}

