              if (state is TaskError) {
                ElegantNotification.error(
                    description: const Text(
                  "data not found",
                  style: TextStyle(color: ColorPallete.backgroundPrimary),
                )).show(context);
              }
            },
            builder: (context, state) {
              if (state is TaskLoading) {
                return const Center(
                    child: CircularProgressIndicator.adaptive());
              }
              if (state is TaskSuccess) {
                debugPrint(
                  state.tasks.toString(),
                );
                for (var i in state.tasks) {
                  debugPrint(
                    i.status,
                  );
                }
                return TaskWidgetHolder(
                  text: Text('Pending',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                  children: [
                    for (var task in state.tasks)
                      if (task.status == "Pending" && _initialValue == "All")
                        TaskWidgetBox(task: task)
                      else if (task.status == "Pending" &&
                          _initialValue == "Team Tasks" &&
                          task.team != null)
                        TaskWidgetBox(
                          task: task,
                        )
                      else if (task.status == "Pending" &&
                          _initialValue == "Team Tasks" &&
                          task.project != null)
                        TaskWidgetBox(task: task)
                  ],
                );
              } else {
                return TaskWidgetHolder(
                  text: Text('Pending',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                  children: const [],
                );
              }
            },
          ),
          const VerticalDivider(
            color: ColorPallete.textPrimary,
            thickness: 2,
          ),
          BlocBuilder<TaskBloc, TaskState>(
            builder: (context, state) {
              if (state is TaskSuccess) {
                return TaskWidgetHolder(
                  text: Text('In Progress',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                  children: [
                    for (var task in state.tasks)
                      if (task.status == "In Progress" &&
                          _initialValue == "All")
                        TaskWidgetBox(task: task)
                      else if (task.status == "In Progress" &&
                          _initialValue == "Team Tasks" &&
                          task.team != null)
                        TaskWidgetBox(
                          task: task,
                        )
                      else if (task.status == "In Progress" &&
                          _initialValue == "Team Tasks" &&
                          task.project != null)
                        TaskWidgetBox(task: task)
                  ],
                );
              }
              return TaskWidgetHolder(
                text: Text('In Progress',
                    style: taskStyle!.copyWith(fontSize: width * 0.015)),
                children: const [],
              );
            },
          ),
          const VerticalDivider(
            color: ColorPallete.textPrimary,
            thickness: 2,
          ),
          BlocBuilder<TaskBloc, TaskState>(
            builder: (context, state) {
              if (state is TaskSuccess) {
                return TaskWidgetHolder(
                  text: Text('Done',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                  children: [
                    for (var task in state.tasks)
                      if (task.status == "Done" && _initialValue == "All")
                        TaskWidgetBox(task: task)
                      else if (task.status == "Done" &&
                          _initialValue == "Team Tasks" &&
                          task.team != null)
                        TaskWidgetBox(
                          task: task,
                        )
                      else if (task.status == "Done" &&
                          _initialValue == "Team Tasks" &&
                          task.project != null)
                        TaskWidgetBox(task: task)
                  ],
                );
              }
              return TaskWidgetHolder(
                text: Text('Done',
                    style: taskStyle!.copyWith(fontSize: width * 0.015)),
                children: const [],
              );
            },
          ),
          const VerticalDivider(
            color: ColorPallete.textPrimary,
            thickness: 2,
          ),
          BlocBuilder<TaskBloc, TaskState>(
            builder: (context, state) {
              if (state is TaskSuccess) {
                return TaskWidgetHolder(
                  text: Text('Blocked',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                  children: [
                    for (var task in state.tasks)
                      if (task.status == "Blocked" && _initialValue == "All")
                        TaskWidgetBox(task: task)
                      else if (task.status == "Blocked" &&
                          _initialValue == "Team Tasks" &&
                          task.team != null)
                        TaskWidgetBox(
                          task: task,
                        )
                      else if (task.status == "Blocked" &&
                          _initialValue == "Team Tasks" &&
                          task.project != null)
                        TaskWidgetBox(task: task)
                  ],
                );
              }
              return TaskWidgetHolder(
                text: Text('Blocked',
                    style: taskStyle!.copyWith(fontSize: width * 0.015)),
                children: const [],
              );
            },
          ),
        ],
      ),
    );
  }

  Padding _belowAppBar(double width, TextStyle? taskStyle) {
    return Padding(
      padding: const EdgeInsets.symmetric(horizontal: 20, vertical: 20),
      child: Row(
        mainAxisAlignment: MainAxisAlignment.spaceBetween,
        crossAxisAlignment: CrossAxisAlignment.center,
        children: [
          Container(
            padding: const EdgeInsets.symmetric(horizontal: 10),
            decoration: BoxDecoration(
              color: ColorPallete.textSecondary,
              borderRadius: BorderRadius.circular(10),
            ),
            width: width * 0.15,
            child: DropdownButton<String>(
              icon: const Icon(Icons.arrow_drop_down_outlined),
              isExpanded: true,
              focusColor: ColorPallete.transparent,
              underline: const SizedBox(),
              value: _initialValue,
              style: taskStyle,
              items: [
                DropdownMenuItem<String>(
                  value: 'All',
                  onTap: () {
                    setState(() {
                      _initialValue = 'All';
                    });
                  },
                  child: Text('All',
                      style: taskStyle!.copyWith(fontSize: width * 0.015)),
                ),
                DropdownMenuItem<String>(
                  value: 'Team Tasks',
                  onTap: () {
                    setState(() {
                      _initialValue = 'Team Tasks';
                    });
                  },
                  child: Text('Team Tasks',
                      style: taskStyle.copyWith(fontSize: width * 0.015)),
                ),
                DropdownMenuItem<String>(
                  value: 'Personal Tasks',
                  onTap: () {
                    setState(() {
                      _initialValue = 'Personal Tasks';
                    });
                  },
                  child: Text('Personal Tasks',
                      style: taskStyle.copyWith(fontSize: width * 0.015)),
                ),
                DropdownMenuItem<String>(
                  value: 'Project Tasks',
                  onTap: () {
                    setState(() {
                      _initialValue = 'Project Tasks';
                    });
                  },
                  child: Text('Project Tasks',
                      style: taskStyle.copyWith(fontSize: width * 0.015)),
                ),
              ],
              onChanged: (value) {},
            ),
          ),
          CustomTextButton(
            width: width * 0.15,
            text: Text(
              'Create Task',
              maxLines: 1,
              overflow: TextOverflow.ellipsis,
              style: taskStyle.copyWith(fontSize: width * 0.015),
            ),
            onTap: () {
              showDialog(
                  context: context,
                  builder: (context) => const Dialog(
                      backgroundColor: ColorPallete.transparent,
                      child: CreateTaskPopUp()));
            },
          ),
        ],
      ),
    );
  }

  CustomAppBar _appBar(BuildContext context) {
    return CustomAppBar(
      children: [
        Text(
          'TASK',
          style: Theme.of(context).textTheme.headlineSmall,
        ),
        const Spacer(),
        IconButton(
          onPressed: () {
