    on<GetTeams>((event, emit) async {
      final result = await _getTeamUseCase.call(event.token);
      result.fold((l) => emit(GetTeamsFailure(error: l)), (r) => emit(GetTeamsSuccess(teams: r)));
    });
  }
}

