class User {
  UserEntity? user;
  String? token;
  Organisation? organisation;
  EmpModel? employee;
  String? employeeToken;
  User({
    this.user,
    this.token,
    this.organisation,
    this.employee,
    this.employeeToken,
  });

  String get role {
    final t = employee?.type;
    if (t == 'owner' || t == 'boss') {
      return 'boss';
    }
    if (t == 'manager') {
      return 'manager';
    }
    return 'employee';
  }

  @override
  toString() {
    if (organisation == null) {
      debugPrint("No Org");
    }
    if (employee == null) {
      debugPrint("No Emp");
    }
    if (user == null) {
      debugPrint("No User");
    }
    return "{}{}{}";
  }
}

