    required this.content,
    this.outcome,
    this.linkedTaskId,
    required this.occurredAt,
    required this.createdAt,
  });

  @override
  List<Object?> get props => [
        id,
        contactId,
        createdById,
        createdByName,
        createdByAvatarUrl,
        type,
        content,
        outcome,
        linkedTaskId,
        occurredAt,
        createdAt,
      ];
}

