    this.saveMessage,
    this.errorMessage,
    this.savedDocument,
  });

  MarkdownEditorState copyWith({
    bool? isLoading,
    bool? isSaving,
    int? documentId,
    int? researchId,
    int? folderId,
    String? title,
    String? content,
    List<ResearchFileEntity>? files,
    List<ResearchReferenceEntity>? references,
    String? saveMessage,
    String? errorMessage,
